 71	// Convert an integer to an array of bytes - little-endian format
 72	void int_to_bytes(int num, uint8_t *bytes, size_t num_bytes)
 73	{
 74	  for (size_t i = 0; i < num_bytes; ++i) {
 75	    bytes[i] = (num >> (i * 8)) & 0xFF;
 76	  }
 77	}
