162	// create shared memory
163	int create_shm(char **addrN, const char *shm_path, int projectId)
164	{
165	  int fd = -1;
166	  key_t key = -1;
167	  int shm_id = -1;
168	  char *addr = NULL;
169	
170	  // Open the file and store the file descriptor
171	  fd = open(shm_path, O_CREAT, 0777);
172	  if (fd == -1) {
173	    err_exit("Error: open shared memory");
174	  }
175	
176	  // Generate key from the file path
177	  key = ftok(shm_path, projectId);
178	  if (key < 0) {
179	    close(fd);
180	    err_exit("Error: ftok error");
181	  }
182	
183	  // Try to create a new shared memory segment
184	  shm_id = shmget(key, SHMSIZE, IPC_CREAT | IPC_EXCL | 0664);
185	  if (shm_id == -1) {
186	    if (errno == EEXIST) {
187	      printf("Error: shared memory already exist\n");
188	      // Get the existing shared memory segment
189	      shm_id = shmget(key, 0, 0);
190	      if (shm_id == -1) {
191	        close(fd);
192	        err_exit("Error: shmget (retrieve existing) failed");
193	      }
194	      printf("reference shm_id = %d\n", shm_id);
195	    } else {
196	      perror("errno");
197	      close(fd);
198	      err_exit("shmget error");
199	    }
200	  }

Exit code: 0
  }

  // Attach to the shared memory segment
  addr = shmat(shm_id, 0, 0);
  if (addr == (void *)-1) {
    printf("Attach shared memory failed\n");
    // Clean up the shared memory segment
    if (shmctl(shm_id, IPC_RMID, NULL) == -1) {
      close(fd);
      err_exit("Error: shmctl error");
    }
    printf("remove shared memory identifier successful\n");
    close(fd);
    err_exit("shmat error");
  }

  // Success - close the file descriptor and return
  close(fd);
  *addrN = addr;
  return shm_id;
}
